            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control @(_confirmMismatch ? "is-invalid" : "")"
                       @bind="_confirmPassword" />
                @if (_confirmMismatch)
                {
                    <div class="invalid-feedback">Passwords do not match.</div>
                }
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
