@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool _confirmMismatch => !string.IsNullOrEmpty(_confirmPassword) && _newPassword != _confirmPassword;

    private async Task UpdatePasswordAsync()
    {
        _statusMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "Passwords do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

