@using sv_85f9a7d0e98f47f9b91f1257cbb70146.Services

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="() => _expanded = !_expanded">
        <h6 class="mb-0">🔑 Change Password</h6>
        <span class="chevron @(_expanded ? "expanded" : "")">▸</span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            @if (!string.IsNullOrEmpty(_statusMessage))
            {
                <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @_statusMessage
                    <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label">Current Password</label>
                <input type="password" class="form-control" @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">New Password</label>
                <input type="password" class="form-control" @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label">Confirm New Password</label>
                <input type="password" class="form-control @(_confirmMismatch ? "is-invalid" : "")"
                       @bind="_confirmPassword" />
                @if (_confirmMismatch)
                {
                    <div class="invalid-feedback">Passwords do not match.</div>
                }
            </div>

            <button class="btn btn-warning" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public ISettingsService SettingsService { get; set; } = default!;

    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private bool _confirmMismatch => !string.IsNullOrEmpty(_confirmPassword) && _newPassword != _confirmPassword;

    private async Task UpdatePasswordAsync()
    {
        _statusMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _statusMessage = "Please fill in all password fields.";
            _isError = true;
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _statusMessage = "Passwords do not match.";
            _isError = true;
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _statusMessage = "Password updated successfully!";
            _isError = false;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to update password: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

