@using sv_85f9a7d0e98f47f9b91f1257cbb70146.Services

@if (_visible)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="Cancel"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@Session?.Device</strong> in <strong>@Session?.Location</strong>?</p>
                    <p class="text-muted small">This will sign out the device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="Cancel" disabled="@_revoking">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmAsync" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private bool _visible;
    private bool _revoking;

    [Parameter] public ActiveSession? Session { get; set; }
    [Parameter] public EventCallback<string> OnConfirm { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    protected override void OnParametersSet()
    {
        _visible = Session is not null;
    }

    private async Task ConfirmAsync()
    {
        if (Session is null) return;
        _revoking = true;
        try
        {
            await OnConfirm.InvokeAsync(Session.Id);
        }
        finally
        {
            _revoking = false;
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

