+        <div class="d-flex justify-content-center py-5">
+            <div class="spinner-border text-primary" role="status">
+                <span class="visually-hidden">Loading...</span>
+            </div>
+        </div>
+    }
+    else
+    {
+        @if (!string.IsNullOrEmpty(_statusMessage))
+        {
+            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
+                @_statusMessage
+                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
+            </div>
+        }
+
+        <ChangePasswordPanel SettingsService="SettingsService" />
+
+        <div class="card mb-4">
+            <div class="card-body d-flex justify-content-between align-items-center">
+                <div>
+                    <h6 class="mb-1">Two-Factor Authentication</h6>
+                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
+                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
+                    </span>
+                    @if (_settings?.LastPasswordChange is not null)
+                    {
+                        <small class="text-muted ms-3">
+                            Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")
+                        </small>
+                    }
+                </div>
+                <div class="form-check form-switch">
+                    <input class="form-check-input" type="checkbox" role="switch" id="twoFactor"
+                           checked="@_twoFactorEnabled" disabled
+                           title="Contact your administrator to change 2FA settings" />
+                </div>
+            </div>
+        </div>
+
+        <div class="card mb-4">
+            <div class="card-header">
+                <h6 class="mb-0">Active Sessions</h6>
+            </div>
+            <div class="table-responsive">
+                <table class="table table-hover mb-0">
+                    <thead>
+                        <tr>
+                            <th>Device</th>
+                            <th>Location</th>
+                            <th>Last Active</th>
+                            <th class="text-end">Action</th>
+                        </tr>
+                    </thead>
+                    <tbody>
+                        @if (_sessions.Count == 0)
+                        {
+                            <tr>
+                                <td colspan="4" class="text-center text-muted py-3">No active sessions.</td>
+                            </tr>
+                        }
+                        else
+                        {
+                            @foreach (var session in _sessions)
+                            {
+                                var isCurrent = session == _sessions[0];
+                                <tr>
+                                    <td>
+                                        @session.Device
+                                        @if (isCurrent)
+                                        {
+                                            <span class="badge bg-primary ms-1">Current</span>
+                                        }
+                                    </td>
+                                    <td>@session.Location</td>
+                                    <td>@FormatLastActive(session.LastActive)</td>
+                                    <td class="text-end">
+                                        @if (!isCurrent)
+                                        {
+                                            <button class="btn btn-outline-danger btn-sm"
+                                                    @onclick="() => _sessionToRevoke = session">
+                                                Revoke
+                                            </button>
+                                        }
+                                    </td>
+                                </tr>
+                            }
+                        }
+                    </tbody>
+                </table>
+            </div>
+        </div>
+
+        <RevokeSessionDialog Session="@_sessionToRevoke"
+                             OnConfirm="RevokeSessionAsync"
+                             OnCancel="() => _sessionToRevoke = null" />
+    }
+</div>
+
+@code {
+    private SecuritySettings? _settings;
+    private bool _twoFactorEnabled;
+    private List<ActiveSession> _sessions = new();
+    private ActiveSession? _sessionToRevoke;
+
+    private bool _loading = true;
+    private string? _statusMessage;
+    private bool _isError;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadAsync();
+    }
+
+    private async Task LoadAsync()
+    {
+        _loading = true;
+        try
+        {
+            _settings = await SettingsService.GetSecuritySettingsAsync();
+            _twoFactorEnabled = _settings.TwoFactorEnabled;
+            _sessions = _settings.Sessions.ToList();
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private async Task RevokeSessionAsync(string sessionId)
+    {
+        _statusMessage = null;
+        try
+        {
+            await SettingsService.RevokeSessionAsync(sessionId);
+            _sessions.RemoveAll(s => s.Id == sessionId);
+            _sessionToRevoke = null;
+            _statusMessage = "Session revoked successfully.";
+            _isError = false;
+        }
+        catch (Exception ex)
+        {
+            _statusMessage = $"Failed to revoke session: {ex.Message}";
+            _isError = true;
+            _sessionToRevoke = null;
+        }
+    }
+
+    private static string FormatLastActive(DateTime lastActive)
+    {
+        var elapsed = DateTime.UtcNow - lastActive;
+        if (elapsed.TotalMinutes < 1) return "Just now";
+        if (elapsed.TotalHours < 1) return $"{(int)elapsed.TotalMinutes}m ago";
+        if (elapsed.TotalDays < 1) return $"{(int)elapsed.TotalHours}h ago";
+        return lastActive.ToString("MMM dd, yyyy HH:mm");
+    }
+}
+

toolArgs.file_text:
@using sv_85f9a7d0e98f47f9b91f1257cbb70146.Services
@inject ISettingsService SettingsService

<div class="appearance-section">
    <h4 class="mb-4">Appearance Settings</h4>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border text-primary" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_statusMessage))
        {
            <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_statusMessage
                <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-7">
                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Theme</h6>
                        @foreach (var theme in _themes)
                        {
                            <div class="form-check mb-2">
                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme.Key}")"
                                       value="@theme.Key" checked="@(_theme == theme.Key)"
                                       @onchange="() => _theme = theme.Key" />
                                <label class="form-check-label" for="@($"theme-{theme.Key}")">@theme.Label</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Font Size</h6>
                        @foreach (var size in _fontSizes)
                        {
                            <div class="form-check form-check-inline">
                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size.Key}")"
                                       value="@size.Key" checked="@(_fontSize == size.Key)"
                                       @onchange="() => _fontSize = size.Key" />
                                <label class="form-check-label" for="@($"fs-{size.Key}")">@size.Label</label>
                            </div>
                        }
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body">
                        <h6 class="card-title mb-3">Language</h6>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _languages)
                            {
                                <option value="@lang.Key">@lang.Label</option>
                            }
                        </select>
                    </div>
                </div>

                <div class="card mb-4">
                    <div class="card-body d-flex justify-content-between align-items-center">
                        <div>
                            <h6 class="mb-1">Compact Mode</h6>
                            <small class="text-muted">Reduce spacing and padding throughout the UI</small>
                        </div>
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" role="switch" id="compactMode"
                                   @bind="_compactMode" />
                        </div>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" role="status"></span>
                    }
                    Save
                </button>
            </div>

            <div class="col-md-5">
                <div class="card">
                    <div class="card-header">
                        <h6 class="mb-0">Live Preview</h6>
                    </div>
                    <div class="card-body preview-area @GetPreviewClasses()">
                        <div class="preview-header mb-2">
                            <strong>Dashboard</strong>
                        </div>
                        <p class="preview-text">
                            This is how your content will look with the selected settings.
                        </p>
                        <div class="d-flex gap-2 mb-2">
                            <span class="badge bg-primary">Tag 1</span>
                            <span class="badge bg-secondary">Tag 2</span>
                        </div>
                        <button class="btn btn-sm btn-outline-primary">Sample Button</button>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;

    private bool _loading = true;
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    private static readonly (string Key, string Label)[] _themes =
        [("Light", "Light ☀️"), ("Dark", "Dark 🌙"), ("System", "System 💻")];

    private static readonly (string Key, string Label)[] _fontSizes =
        [("Small", "Small"), ("Medium", "Medium"), ("Large", "Large")];

    private static readonly (string Key, string Label)[] _languages =
    [
        ("en", "English"),
        ("es", "Español"),
        ("fr", "Français"),
        ("de", "Deutsch"),
        ("ja", "日本語"),
        ("zh", "中文")
    ];

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        try
        {
            var settings = await SettingsService.GetAppearanceAsync();
            _theme = settings.Theme;
            _fontSize = settings.FontSize;
            _language = settings.Language;
            _compactMode = settings.CompactMode;
        }
        finally
        {
            _loading = false;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();

        classes.Add(_theme switch
        {
            "Dark" => "preview-dark",
            _ => "preview-light"
        });

        classes.Add(_fontSize switch
        {
            "Small" => "preview-font-small",
            "Large" => "preview-font-large",
            _ => "preview-font-medium"
        });

        if (_compactMode)
            classes.Add("preview-compact");

        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            _statusMessage = "Appearance settings saved!";
            _isError = false;
        }
        catch (Exception ex)
        {
            _statusMessage = $"Failed to save: {ex.Message}";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }
}

