+        _loading = true;
+        try
+        {
+            var settings = await SettingsService.GetAppearanceAsync();
+            _theme = settings.Theme;
+            _fontSize = settings.FontSize;
+            _language = settings.Language;
+            _compactMode = settings.CompactMode;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private string GetPreviewClasses()
+    {
+        var classes = new List<string>();
+
+        classes.Add(_theme switch
+        {
+            "Dark" => "preview-dark",
+            _ => "preview-light"
+        });
+
+        classes.Add(_fontSize switch
+        {
+            "Small" => "preview-font-small",
+            "Large" => "preview-font-large",
+            _ => "preview-font-medium"
+        });
+
+        if (_compactMode)
+            classes.Add("preview-compact");
+
+        return string.Join(" ", classes);
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        _statusMessage = null;
+        try
+        {
+            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+            await SettingsService.SaveAppearanceAsync(settings);
+            _statusMessage = "Appearance settings saved!";
+            _isError = false;
+        }
+        catch (Exception ex)
+        {
+            _statusMessage = $"Failed to save: {ex.Message}";
+            _isError = true;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

