@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard d-flex">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content flex-grow-1 p-4">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

