    min-height: calc(100vh - 120px);
    border: 1px solid var(--bs-border-color);
    border-radius: 0.5rem;
    overflow: hidden;
    background-color: var(--bs-body-bg);
}

.settings-content {
    overflow-y: auto;
    max-width: 900px;
}

